using System.ComponentModel;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace McpApiServer.Tools;

/// <summary>
/// MCP tools that call an external API via HttpClient.
/// HttpClient and ILogger are injected by the DI container and do not appear in the tool schema.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Fetch a resource from the external API by its unique identifier.")]
    public async Task<string> FetchResource(
        [Description("The unique identifier of the resource to retrieve")] string id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching resource {Id}", id);
        var response = await httpClient.GetAsync($"/api/resources/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Search the external API for resources matching a query string.")]
    public async Task<string> SearchResources(
        [Description("The search query to filter resources")] string query,
        [Description("Maximum number of results to return (1-50)")] int maxResults = 10,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching resources with query={Query}, max={Max}", query, maxResults);
        var response = await httpClient.GetAsync(
            $"/api/resources?q={Uri.EscapeDataString(query)}&limit={maxResults}",
            cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

using System.ComponentModel;
using Microsoft.Extensions.AI;
using ModelContextProtocol.Server;

namespace McpApiServer.Prompts;

/// <summary>
/// Prompt templates for content summarization.
/// </summary>
[McpServerPromptType]
public static class SummarizationPrompts
{
    [McpServerPrompt, Description("Summarize the provided content into a concise paragraph.")]
    public static ChatMessage Summarize(
        [Description("The content to summarize")] string content) =>
        new(ChatRole.User, $"Summarize the following content into a single concise paragraph:\n\n{content}");

    [McpServerPrompt, Description("Summarize the provided content as a bullet-point list of key takeaways.")]
    public static ChatMessage SummarizeAsBullets(
        [Description("The content to extract key points from")] string content) =>
        new(ChatRole.User, $"Extract the key takeaways from the following content as a concise bullet-point list:\n\n{content}");
}

